package org;

import org.controller.MF;
import org.controller.VC;
import org.model.Jeu;

public class Main {
    public static void main(String[] args) {
        Jeu j = new Jeu();
        MF mf = new MF();
        mf.setJeu(j);
        j.addObserver(mf);
        VC vue = new VC(j);
        mf.setVC(vue);
        j.addObserver(vue);
        mf.setVisible(true);
    }
}

package org;

import org.controller.MF;
import org.controller.VC;
import org.model.Jeu;
import org.view.VueConsole;

public class Main {
    public static void main(String[] args) {
        Jeu j = new Jeu();

        // ── Vue graphique ────────────────────────────────────────────────
        MF mf = new MF();
        mf.setJeu(j);
        j.addObserver(mf);
        VC vue = new VC(j);
        mf.setVC(vue);
        j.addObserver(vue);
        mf.setVisible(true);

        // ── Vue console (même modèle, aucune modification du modèle) ─────
        VueConsole console = new VueConsole(j);
        j.addObserver(console);
    }
}

package org.controller;

import org.model.Jeu;

import javax.swing.*;
import java.awt.*;
import java.util.Observable;
import java.util.Observer;

public class MF extends JFrame implements Observer {

    public Jeu jeu;
    private JLabel statusLabel;
    private JPanel boardHolder;

    public MF() {
        super("MF Window");
        setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
        setSize(600, 600);
        setLayout(new BorderLayout());
        statusLabel = new JLabel("MF initialisé", SwingConstants.CENTER);
        add(statusLabel, BorderLayout.NORTH);
        boardHolder = new JPanel(new BorderLayout());
        add(boardHolder, BorderLayout.CENTER);
    }

    public void setJeu(Jeu j) {
        this.jeu = j;
    }

    public void setVC(VC vc) {
        boardHolder.removeAll();
        boardHolder.add(vc.getPanel(), BorderLayout.CENTER);
        revalidate();
        repaint();
    }

    @Override
    public void update(Observable o, Object arg) {
        SwingUtilities.invokeLater(() -> {
            String msg = "Update rereçu";
            if (arg != null) {
                String argStr = arg.toString();
                if (argStr.contains("ÉCHEC ET MAT")) {
                    msg = argStr ;
                } else if (argStr.contains("PAT")) {
                    msg = argStr ;
                } else if (argStr.contains("ÉCHEC")) {
                    msg = "ÉCHEC ! ";
                } else {
                    msg = argStr;
                }
            }
            statusLabel.setText(msg);
            repaint();
        });
    }
}

package org.controller;

import org.model.Coup;
import org.model.Jeu;
import org.model.piece.Piece;
import org.model.plateau.Case;

import javax.swing.*;
import java.awt.*;
import java.awt.event.*;
import java.util.ArrayList;
import java.util.List;
import java.util.Observable;
import java.util.Observer;

/**
 * CONTRÔLEUR — responsabilités strictes MVC :
 *   (1) Récupère les événements Swing (MouseListeners enregistrés sur la Vue)
 *   (2) Répercussions locales directes sur la Vue sans exploitation du Modèle
 *       (surlignage, bordure de sélection, fenêtre fantôme de drag)
 *   (3) Déclenche les traitements du Modèle (jeu.setCoup, jeu.nouvellePartie)
 *
 * Le Contrôleur est aussi Observer pour :
 *   – réinitialiser son état interne après chaque coup (supprime les highlights
 *     restants non encore nettoyés)
 *   – afficher le dialogue de fin de partie et déclencher une nouvelle partie
 */
public class MF extends JFrame implements Observer {

    // ── Références ────────────────────────────────────────────────────────────
    private Jeu  jeu;
    private VC   vue;

    // ── État interne du Contrôleur (interaction en cours) ────────────────────
    private Point  depart;
    private JPanel draggingPanel;
    private JWindow dragWindow;
    private Point  dragOffset;
    private final List<Point> casesHighlightees = new ArrayList<>();

    // ── Listener global pour le drag en dehors de l'échiquier ────────────────
    private AWTEventListener globalMouseListener;

    // ── Composant d'affichage interne du Contrôleur ──────────────────────────
    private JLabel    statusLabel;
    private JPanel    boardHolder;

    // ─────────────────────────────────────────────────────────────────────────

    public MF() {
        super("Jeu d'Échecs");
        setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
        setSize(700, 750);
        setLayout(new BorderLayout());

        statusLabel = new JLabel("Contrôleur initialisé", SwingConstants.CENTER);
        statusLabel.setFont(new Font("SansSerif", Font.PLAIN, 12));
        add(statusLabel, BorderLayout.NORTH);

        boardHolder = new JPanel(new BorderLayout());
        add(boardHolder, BorderLayout.CENTER);
    }

    // ── Injection des dépendances (appelé depuis Main) ────────────────────────

    public void setJeu(Jeu j) {
        this.jeu = j;
    }

    /**
     * Intègre la Vue dans la fenêtre et enregistre les MouseListeners
     * sur tous les panneaux de cases — étape (1) du MVC.
     */
    public void setVC(VC vc) {
        this.vue = vc;

        // Intégration graphique
        boardHolder.removeAll();
        boardHolder.add(vc.getPanel(), BorderLayout.CENTER);
        revalidate();
        repaint();

        // ── Étape (1) : enregistrement des événements Swing ──────────────────
        for (int l = 0; l < 8; l++) {
            for (int c = 0; c < 8; c++) {
                final int ligne   = l;
                final int colonne = c;
                JPanel casePanel  = vc.getCasePanel(l, c);

                casePanel.addMouseListener(new MouseAdapter() {
                    @Override public void mousePressed (MouseEvent e) { onPressed (ligne, colonne, e); }
                    @Override public void mouseReleased(MouseEvent e) { onReleased(ligne, colonne, e); }
                    @Override public void mouseEntered (MouseEvent e) { onEntered (ligne, colonne);    }
                    @Override public void mouseExited  (MouseEvent e) { onExited  (ligne, colonne);    }
                });

                casePanel.addMouseMotionListener(new MouseMotionAdapter() {
                    @Override public void mouseDragged(MouseEvent e) { onDragged(e); }
                });
            }
        }

        // ── Listener global pour détecter le relâchement hors plateau ────────
        globalMouseListener = evt -> {
            if (!(evt instanceof MouseEvent)) return;
            MouseEvent me = (MouseEvent) evt;
            if      (me.getID() == MouseEvent.MOUSE_RELEASED) onGlobalReleased(me);
            else if (me.getID() == MouseEvent.MOUSE_DRAGGED && dragWindow != null && dragOffset != null) {
                dragWindow.setLocation(me.getXOnScreen() - dragOffset.x,
                                       me.getYOnScreen() - dragOffset.y);
            }
        };
        Toolkit.getDefaultToolkit().addAWTEventListener(globalMouseListener,
                AWTEvent.MOUSE_EVENT_MASK | AWTEvent.MOUSE_MOTION_EVENT_MASK);

        // ── Menu « Partie → Nouvelle partie » (étape 1 + déclenchement étape 3)
        JMenuBar menuBar = new JMenuBar();
        JMenu menuPartie = new JMenu("Partie");
        JMenuItem newGame = new JMenuItem("Nouvelle partie");
        newGame.setAccelerator(KeyStroke.getKeyStroke(KeyEvent.VK_N, InputEvent.META_DOWN_MASK));
        newGame.addActionListener(e ->                          // étape (1)
                new Thread(jeu::nouvellePartie, "Reset-Thread").start() // étape (3)
        );
        menuPartie.add(newGame);
        menuBar.add(menuPartie);
        setJMenuBar(menuBar);
    }

    // ══════════════════════════════════════════════════════════════════════════
    // Étape (1) → (2) → (3)  Handlers des événements Swing
    // ══════════════════════════════════════════════════════════════════════════

    /** (1) Pression de souris — sélection de la pièce. */
    private void onPressed(int ligne, int colonne, MouseEvent e) {
        synchronized (jeu) {
            // (2) Effacer les anciens surlignages (effet local, pas de Modèle)
            clearAllHighlights();

            JLabel source = vue.getCaseLabel(ligne, colonne);
            if (source.getIcon() == null && (source.getText() == null || source.getText().isEmpty())) {
                return; // case vide
            }

            depart        = new Point(ligne, colonne);
            draggingPanel = vue.getCasePanel(ligne, colonne);

            // (2) Bordure jaune sur la case sélectionnée
            vue.setCaseBorder(ligne, colonne, BorderFactory.createLineBorder(Color.YELLOW, 3));

            // (3) Interroger le Modèle pour les cases accessibles, puis (2) les surligner
            Piece piece = jeu.getEchiquier().getPiece(ligne, colonne);
            if (piece != null) {
                System.out.println("MF: compute targets for " + piece.getClass().getSimpleName()
                        + " at (" + ligne + "," + colonne + ") color=" + (piece.isBlanc() ? "W" : "B"));
                for (Case tgt : piece.getCaseAccessible()) {
                    if (tgt == null) continue;
                    int x = tgt.getX(), y = tgt.getY();
                    if (x >= 0 && x < 8 && y >= 0 && y < 8) {
                        vue.setHighlight(x, y);            // (2) effet local direct
                        casesHighlightees.add(new Point(x, y));
                    }
                }
            }

            // (2) Fenêtre fantôme de drag (effet visuel local, pas de Modèle)
            Icon icon = source.getIcon();
            JLabel ghost = (icon != null)
                    ? new JLabel(icon)
                    : new JLabel(source.getText(), SwingConstants.CENTER);
            dragWindow = new JWindow();
            dragWindow.getContentPane().add(ghost);
            dragWindow.pack();
            dragOffset = new Point(dragWindow.getWidth() / 2, dragWindow.getHeight() / 2);
            dragWindow.setLocation(e.getXOnScreen() - dragOffset.x, e.getYOnScreen() - dragOffset.y);
            dragWindow.setVisible(true);
        }
    }

    /** (1) Relâchement de souris — soumission du coup au Modèle. */
    private void onReleased(int ligne, int colonne, MouseEvent e) {
        synchronized (jeu) {
            clearAllHighlights(); // (2) nettoyage immédiat
            if (depart != null) {
                jeu.setCoup(new Coup(depart, new Point(ligne, colonne))); // (3) → Modèle
                depart = null;
            }
            cleanupDrag(); // (2) suppression fenêtre fantôme
        }
    }

    /** (1) Survol — effet de hover local. */
    private void onEntered(int ligne, int colonne) {
        if (!casesHighlightees.contains(new Point(ligne, colonne)))
            vue.setHover(ligne, colonne); // (2) couleur rouge, pas de Modèle
    }

    /** (1) Sortie de case — restauration couleur. */
    private void onExited(int ligne, int colonne) {
        if (!casesHighlightees.contains(new Point(ligne, colonne)))
            vue.clearHover(ligne, colonne); // (2) effet local direct
    }

    /** (1) Drag — déplacement de la fenêtre fantôme. */
    private void onDragged(MouseEvent e) {
        if (dragWindow != null && dragOffset != null)
            dragWindow.setLocation(e.getXOnScreen() - dragOffset.x,
                                   e.getYOnScreen() - dragOffset.y); // (2)
    }

    /** (1) Relâchement global (hors plateau) — calcule la case cible. */
    private void onGlobalReleased(MouseEvent me) {
        synchronized (jeu) {
            if (depart == null) return;
            JPanel boardPanel = vue.getPanel();
            if (!boardPanel.isShowing()) { cleanupDrag(); depart = null; return; }
            try {
                Point origin = boardPanel.getLocationOnScreen();
                int rx = me.getXOnScreen() - origin.x;
                int ry = me.getYOnScreen() - origin.y;
                if (rx < 0 || ry < 0 || rx >= boardPanel.getWidth() || ry >= boardPanel.getHeight()) {
                    cleanupDrag(); depart = null; return;
                }
                int col = Math.min(7, rx / Math.max(1, boardPanel.getWidth()  / 8));
                int row = Math.min(7, ry / Math.max(1, boardPanel.getHeight() / 8));
                clearAllHighlights(); // (2)
                jeu.setCoup(new Coup(new Point(depart.x, depart.y), new Point(row, col))); // (3)
                depart = null;
                cleanupDrag(); // (2)
            } catch (IllegalComponentStateException ex) {
                cleanupDrag(); depart = null;
            }
        }
    }

    // ── Helpers locaux (étape 2 uniquement) ──────────────────────────────────

    private void clearAllHighlights() {
        for (Point p : casesHighlightees) {
            vue.clearHighlight(p.x, p.y);           // (2)
        }
        casesHighlightees.clear();
        if (draggingPanel != null) {
            // Chercher la case de départ pour enlever la bordure
            if (depart != null) vue.setCaseBorder(depart.x, depart.y, null);
            draggingPanel = null;
        }
    }

    private void cleanupDrag() {
        if (depart != null) { vue.setCaseBorder(depart.x, depart.y, null); } // (2)
        draggingPanel = null;
        if (dragWindow != null) {
            try { dragWindow.setVisible(false); dragWindow.dispose(); } catch (Exception ignored) {}
            dragWindow = null;
            dragOffset = null;
        }
    }

    // ══════════════════════════════════════════════════════════════════════════
    // Observer — réception des notifications du Modèle (étape 4)
    // ══════════════════════════════════════════════════════════════════════════

    @Override
    public void update(Observable o, Object arg) {
        if (arg instanceof String) {
            // Fin de partie : le Contrôleur affiche le dialogue et déclenche
            // éventuellement une nouvelle partie (étape 3)
            String msg = (String) arg;
            SwingUtilities.invokeLater(() -> {
                int choice = JOptionPane.showOptionDialog(
                        this,
                        msg + "\n\nVoulez-vous jouer une nouvelle partie ?",
                        "Fin de partie",
                        JOptionPane.YES_NO_OPTION,
                        JOptionPane.INFORMATION_MESSAGE,
                        null,
                        new String[]{"Nouvelle partie", "Quitter"},
                        "Nouvelle partie"
                );
                if (choice == 0) {
                    new Thread(jeu::nouvellePartie, "Reset-Thread").start(); // (3)
                } else {
                    System.exit(0);
                }
            });
        } else if (arg == null) {
            // Nouvelle partie : réinitialiser l'état interne du Contrôleur
            SwingUtilities.invokeLater(() -> {
                depart = null;
                casesHighlightees.clear();
                statusLabel.setText("Nouvelle partie — Tour des BLANCS");
            });
        } else {
            SwingUtilities.invokeLater(() -> statusLabel.setText("Mise à jour reçue"));
        }
    }

    @Override
    public void dispose() {
        if (globalMouseListener != null)
            try { Toolkit.getDefaultToolkit().removeAWTEventListener(globalMouseListener); }
            catch (Exception ignored) {}
        super.dispose();
    }
}

package org.controller;

import org.model.*;
import org.model.piece.Piece;
import org.tools.SvgToPngConverter;

import javax.swing.*;
import java.awt.*;
import java.awt.event.AWTEventListener;
import java.awt.event.MouseAdapter;
import java.awt.event.MouseEvent;
import java.awt.image.BufferedImage;
import java.io.InputStream;
import java.util.Observable;
import java.util.Observer;

public class VC extends JFrame implements Observer {

    private final Jeu jeu;
    private Point depart;
    private JPanel panel;
    private JPanel draggingPanel;
    private JWindow dragWindow;
    private Point dragOffset;
    private AWTEventListener globalMouseListener;
    private Color BEIGE = new Color(240, 217, 181);
    private Color MARRON = new Color(181, 136, 99);
    private Color HIGHLIGHT = new Color(100, 200, 100);
    private java.util.List<Point> casesAccessiblesHighlightees = new java.util.ArrayList<>();
    private JLabel statusLabel;

    private final JPanel[][] casePanels = new JPanel[8][8];
    private final JLabel[][] caseLabels = new JLabel[8][8];

    public VC(Jeu jeu) {
        this.jeu = jeu;
        jeu.addObserver(this);

        setTitle("Jeu d'échecs");
        setSize(650, 680);
        setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);

        // ── Barre de menu ──────────────────────────────────────────────────
        JMenuBar menuBar = new JMenuBar();
        JMenu menuPartie = new JMenu("Partie");
        JMenuItem newGameItem = new JMenuItem("Nouvelle partie");
        newGameItem.setAccelerator(javax.swing.KeyStroke.getKeyStroke(
                java.awt.event.KeyEvent.VK_N,
                java.awt.event.InputEvent.META_DOWN_MASK)); // Cmd+N sur Mac
        newGameItem.addActionListener(e ->
                // Exécuté hors de l'EDT pour ne pas bloquer l'interface
                new Thread(jeu::nouvellePartie, "Reset-Thread").start()
        );
        menuPartie.add(newGameItem);
        menuBar.add(menuPartie);
        setJMenuBar(menuBar);
        // ───────────────────────────────────────────────────────────────────

        panel = new JPanel(new BorderLayout());

        JPanel chessBoard = new JPanel(new GridLayout(8, 8));

        for (int l = 0; l < 8; l++) {
            for (int c = 0; c < 8; c++) {
                JPanel casePanel = new JPanel(new BorderLayout());
                casePanels[l][c] = casePanel;
                JLabel label = new JLabel("", SwingConstants.CENTER);
                caseLabels[l][c] = label;
                casePanel.add(label, BorderLayout.CENTER);

                final int ligne = l;
                final int colonne = c;

                casePanel.addMouseListener(new MouseAdapter() {
                    @Override
                    public void mousePressed(MouseEvent e) {
                        synchronized (jeu) {
                            // clear previous highlights
                            for (Point p : casesAccessiblesHighlightees) {
                                Color couleur = ((p.x + p.y) % 2 == 0) ? BEIGE : MARRON;
                                casePanels[p.x][p.y].setBackground(couleur);
                            }
                            casesAccessiblesHighlightees.clear();

                            depart = new Point(ligne, colonne);
                            draggingPanel = casePanel;
                            casePanel.setBorder(BorderFactory.createLineBorder(Color.YELLOW, 3));

                            Component comp = (casePanel.getComponentCount() > 0) ? casePanel.getComponent(0) : null;
                            JLabel source = (comp instanceof JLabel) ? (JLabel) comp : null;
                            if (source == null || (source.getIcon() == null && (source.getText() == null || source.getText().isEmpty()))) {
                                depart = null;
                                draggingPanel = null;
                                return;
                            }

                            // Highlight all accessible squares (en passant, castling, promotion
                            // are now computed directly by each piece's getCaseAccessible())
                            Piece piece = jeu.getEchiquier().getPiece(ligne, colonne);
                            if (piece != null) {
                                java.util.List<org.model.plateau.Case> casesAccessibles = piece.getCaseAccessible();
                                System.out.println("VC: compute targets for " + piece.getClass().getSimpleName()
                                        + " at (" + ligne + "," + colonne + ") color=" + (piece.isBlanc() ? "W" : "B"));
                                System.out.print("VC: final targets:");
                                for (org.model.plateau.Case tgt : casesAccessibles) {
                                    if (tgt != null) System.out.print(" (" + tgt.getX() + "," + tgt.getY() + ")");
                                }
                                System.out.println();

                                for (org.model.plateau.Case tgt : casesAccessibles) {
                                    if (tgt == null) continue;
                                    int x = tgt.getX();
                                    int y = tgt.getY();
                                    if (x >= 0 && x < 8 && y >= 0 && y < 8) {
                                        casePanels[x][y].setBackground(HIGHLIGHT);
                                        casesAccessiblesHighlightees.add(new Point(x, y));
                                        try { casePanels[x][y].revalidate(); casePanels[x][y].repaint(); } catch (Exception ignored) {}
                                    }
                                }
                            }

                            JLabel ghost;
                            if (source.getIcon() != null) {
                                Icon icon = source.getIcon();
                                ghost = new JLabel(icon);
                            } else {
                                ghost = new JLabel(source.getText(), SwingConstants.CENTER);
                            }

                            dragWindow = new JWindow();
                            dragWindow.getContentPane().add(ghost);
                            dragWindow.pack();
                            int gw = dragWindow.getWidth();
                            int gh = dragWindow.getHeight();
                            dragOffset = new Point(gw / 2, gh / 2);
                            int sx = e.getXOnScreen() - dragOffset.x;
                            int sy = e.getYOnScreen() - dragOffset.y;
                            dragWindow.setLocation(sx, sy);
                            dragWindow.setVisible(true);
                        }
                    }

                    @Override
                    public void mouseReleased(MouseEvent e) {
                        synchronized (jeu) {
                            // clear highlights
                            for (Point p : casesAccessiblesHighlightees) {
                                Color couleur = ((p.x + p.y) % 2 == 0) ? BEIGE : MARRON;
                                casePanels[p.x][p.y].setBackground(couleur);
                                try { casePanels[p.x][p.y].revalidate(); casePanels[p.x][p.y].repaint(); } catch (Exception ignored) {}
                            }
                            casesAccessiblesHighlightees.clear();

                            if (depart != null) {
                                jeu.setCoup(new Coup(depart, new Point(ligne, colonne)));
                                depart = null;
                                if (draggingPanel != null) {
                                    draggingPanel.setBorder(null);
                                    draggingPanel = null;
                                }
                                if (dragWindow != null) {
                                    dragWindow.setVisible(false);
                                    dragWindow.dispose();
                                    dragWindow = null;
                                    dragOffset = null;
                                }
                            }
                        }
                    }

                    @Override
                    public void mouseEntered(MouseEvent e) {
                        if (!casesAccessiblesHighlightees.contains(new Point(ligne, colonne))) {
                            casePanel.setBackground(Color.RED);
                        }
                    }

                    @Override
                    public void mouseExited(MouseEvent e) {
                        if (!casesAccessiblesHighlightees.contains(new Point(ligne, colonne))) {
                            Color couleurOriginale = ((ligne + colonne) % 2 == 0) ? BEIGE : MARRON;
                            casePanel.setBackground(couleurOriginale);
                        }
                    }
                });

                casePanel.addMouseMotionListener(new java.awt.event.MouseMotionAdapter() {
                    @Override
                    public void mouseDragged(MouseEvent e) {
                        if (dragWindow != null && dragOffset != null) {
                            int nx = e.getXOnScreen() - dragOffset.x;
                            int ny = e.getYOnScreen() - dragOffset.y;
                            dragWindow.setLocation(nx, ny);
                        }
                    }
                });

                chessBoard.add(casePanel);
            }
        }

        JPanel rowPanel = new JPanel(new GridLayout(8, 1));
        for (int i = 8; i >= 1; i--) {
            JLabel lbl = new JLabel(" " + i + " ", SwingConstants.CENTER);
            lbl.setFont(new Font("SansSerif", Font.BOLD, 12));
            rowPanel.add(lbl);
        }

        JPanel colPanel = new JPanel(new GridLayout(1, 8));
        for (char c = 'a'; c <= 'h'; c++) {
            JLabel lbl = new JLabel(String.valueOf(c), SwingConstants.CENTER);
            lbl.setFont(new Font("SansSerif", Font.BOLD, 12));
            colPanel.add(lbl);
        }

        JPanel southContainer = new JPanel(new BorderLayout());
        JLabel spacer = new JLabel("   ");
        southContainer.add(spacer, BorderLayout.WEST);
        southContainer.add(colPanel, BorderLayout.CENTER);



        // Status bar
        statusLabel = new JLabel("Tour : BLANCS", SwingConstants.CENTER);
        statusLabel.setFont(new Font("SansSerif", Font.BOLD, 14));
        statusLabel.setBorder(BorderFactory.createEmptyBorder(4, 0, 4, 0));

        panel.add(statusLabel, BorderLayout.NORTH);
        panel.add(rowPanel, BorderLayout.WEST);
        panel.add(chessBoard, BorderLayout.CENTER);
        panel.add(southContainer, BorderLayout.SOUTH);

        add(panel);

        redraw();

        globalMouseListener = evt -> {
            if (!(evt instanceof java.awt.event.MouseEvent)) return;
            MouseEvent me = (MouseEvent) evt;
            if (me.getID() == MouseEvent.MOUSE_RELEASED) {
                handleGlobalMouseReleased(me);
            } else if (me.getID() == MouseEvent.MOUSE_DRAGGED) {
                if (dragWindow != null && dragOffset != null) {
                    int nx = me.getXOnScreen() - dragOffset.x;
                    int ny = me.getYOnScreen() - dragOffset.y;
                    dragWindow.setLocation(nx, ny);
                }
            }
        };
        Toolkit.getDefaultToolkit().addAWTEventListener(globalMouseListener,
                AWTEvent.MOUSE_EVENT_MASK | AWTEvent.MOUSE_MOTION_EVENT_MASK);
    }

    public JPanel getPanel() {
        return panel;
    }

    private void redraw() {
        int panelW = Math.max(1, panel.getWidth());
        int panelH = Math.max(1, panel.getHeight());
        int cellW = Math.max(1, panelW / 8);
        int cellH = Math.max(1, panelH / 8);
        int iconSize = Math.max(32, Math.min(cellW, cellH));

        for (int l = 0; l < 8; l++) {
            for (int c = 0; c < 8; c++) {
                JPanel casePanel = casePanels[l][c];
                JLabel label = caseLabels[l][c];

                Color couleurOriginale = ((l + c) % 2 == 0) ? BEIGE : MARRON;
                casePanel.setBackground(couleurOriginale);

                Piece piece = jeu.getEchiquier().getPiece(l, c);
                if (piece != null) {
                    String imagePath = piece.getImageName();
                    String resourcePath = null;

                    if (imagePath != null && !imagePath.isEmpty()) {
                        String[] exts = new String[]{".svg", ".png", ".jpeg", ".jpg"};
                        for (String ext : exts) {
                            String candidate = "/Pieces/" + imagePath + ext;
                            java.net.URL url = getClass().getResource(candidate);
                            if (url != null) { resourcePath = candidate; break; }
                        }
                        if (resourcePath == null) {
                            for (String ext : exts) {
                                String candidate = "Pieces/" + imagePath + ext;
                                java.net.URL url = getClass().getResource(candidate);
                                if (url != null) { resourcePath = candidate; break; }
                            }
                        }
                    }

                    Icon icon = createSafeIcon(piece, resourcePath, iconSize);
                    label.setIcon(icon);
                    label.setText("");
                } else {
                    label.setIcon(null);
                    label.setText("");
                }
            }
        }

        panel.revalidate();
        panel.repaint();
    }

    private Icon createSafeIcon(Piece piece, String resourcePath, int size) {
        if (resourcePath != null) {
            try {
                String lower = resourcePath.toLowerCase();
                if (lower.endsWith(".svg")) {
                    try (InputStream is = getClass().getResourceAsStream(resourcePath)) {
                        if (is != null) {
                            BufferedImage bi = SvgToPngConverter.loadSvgAsImage(is, size, size);
                            if (bi != null) return new ImageIcon(bi);
                        }
                    } catch (Exception ignored) {}
                }
                java.net.URL url = getClass().getResource(resourcePath);
                if (url != null) {
                    ImageIcon ii = new ImageIcon(url);
                    if (ii.getIconWidth() > 0) {
                        Image img = ii.getImage().getScaledInstance(size, size, Image.SCALE_SMOOTH);
                        return new ImageIcon(img);
                    }
                }
            } catch (Exception ignored) {}
        }

        // Fallback: letter in a circle
        String initial = piece.getClass().getSimpleName().substring(0, 1).toUpperCase();
        BufferedImage bi = new BufferedImage(size, size, BufferedImage.TYPE_INT_ARGB);
        Graphics2D g = bi.createGraphics();
        try {
            g.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);
            g.setColor(new Color(0,0,0,0));
            g.fillRect(0,0,size,size);
            g.setColor(piece.isBlanc() ? new Color(255,255,255,230) : new Color(60,60,60,230));
            g.fillOval(2,2,size-4,size-4);
            g.setColor(piece.isBlanc() ? MARRON : BEIGE);
            Font font = new Font("SansSerif", Font.BOLD, Math.max(12, size/2));
            g.setFont(font);
            FontMetrics fm = g.getFontMetrics();
            g.drawString(initial, (size - fm.stringWidth(initial)) / 2, (size - fm.getHeight()) / 2 + fm.getAscent());
        } finally { g.dispose(); }
        return new ImageIcon(bi);
    }

    private void handleGlobalMouseReleased(MouseEvent me) {
        synchronized (jeu) {
            if (depart == null) return;
            if (!panel.isShowing()) { cleanupDrag(); depart = null; return; }
            try {
                Point panelOnScreen = panel.getLocationOnScreen();
                int rx = me.getXOnScreen() - panelOnScreen.x;
                int ry = me.getYOnScreen() - panelOnScreen.y;
                if (rx < 0 || ry < 0 || rx >= panel.getWidth() || ry >= panel.getHeight()) {
                    cleanupDrag(); depart = null; return;
                }
                int cellW = Math.max(1, panel.getWidth() / 8);
                int cellH = Math.max(1, panel.getHeight() / 8);
                int col = Math.min(7, rx / cellW);
                int row = Math.min(7, ry / cellH);
                jeu.setCoup(new Coup(new Point(depart.x, depart.y), new Point(row, col)));
                depart = null;
                cleanupDrag();
            } catch (IllegalComponentStateException ex) {
                cleanupDrag(); depart = null;
            }
        }
    }

    private void cleanupDrag() {
        if (draggingPanel != null) {
            try { draggingPanel.setBorder(null); } catch (Exception ignored) {}
            draggingPanel = null;
        }
        if (dragWindow != null) {
            try { dragWindow.setVisible(false); dragWindow.dispose(); } catch (Exception ignored) {}
            dragWindow = null;
            dragOffset = null;
        }
    }

    @Override
    public void update(Observable o, Object arg) {
        SwingUtilities.invokeLater(() -> {
            redraw();
            if (arg instanceof String) {
                // Message de fin de partie
                String msg = (String) arg;
                statusLabel.setForeground(Color.RED);
                statusLabel.setText(msg);

                int choice = JOptionPane.showOptionDialog(
                        this,
                        msg + "\n\nVoulez-vous jouer une nouvelle partie ?",
                        "Fin de partie",
                        JOptionPane.YES_NO_OPTION,
                        JOptionPane.INFORMATION_MESSAGE,
                        null,
                        new String[]{"Nouvelle partie", "Quitter"},
                        "Nouvelle partie"
                );
                if (choice == 0) {
                    new Thread(jeu::nouvellePartie, "Reset-Thread").start();
                } else if (choice == 1 || choice == JOptionPane.CLOSED_OPTION) {
                    System.exit(0);
                }
            } else if (arg instanceof Coup) {
                Coup c = (Coup) arg;
                String type = c.getType();
                // joueurCourant is still the player who just moved
                Joueur joueur = jeu.getJoueurCourant();
                String nextPlayer = (joueur != null && joueur.isBlanc()) ? "NOIRS" : "BLANCS";
                switch (type == null ? "" : type) {
                    case "ECHEC":
                        statusLabel.setForeground(new Color(180, 0, 0));
                        statusLabel.setText("ÉCHEC ! — Tour : " + nextPlayer);
                        break;
                    case "ROQUE":
                        statusLabel.setForeground(new Color(0, 100, 180));
                        statusLabel.setText("ROQUE — Tour : " + nextPlayer);
                        break;
                    case "PRISE EN PASSANT":
                        statusLabel.setForeground(new Color(0, 120, 0));
                        statusLabel.setText("PRISE EN PASSANT — Tour : " + nextPlayer);
                        break;
                    case "PROMOTION":
                        statusLabel.setForeground(new Color(120, 0, 120));
                        statusLabel.setText("PROMOTION — Tour : " + nextPlayer);
                        break;
                    default:
                        statusLabel.setForeground(Color.BLACK);
                        statusLabel.setText("Tour : " + nextPlayer);
                }
            } else {
                statusLabel.setForeground(Color.BLACK);
                Joueur joueur = jeu.getJoueurCourant();
                String current = (joueur != null && joueur.isBlanc()) ? "BLANCS" : "NOIRS";
                statusLabel.setText("Tour : " + current);
            }
        });
    }

    @Override
    public void dispose() {
        try { Toolkit.getDefaultToolkit().removeAWTEventListener(globalMouseListener); } catch (Exception ignored) {}
        super.dispose();
    }
}

package org.controller;

import org.model.Coup;
import org.model.Jeu;
import org.model.Joueur;
import org.model.piece.Piece;
import org.tools.SvgToPngConverter;

import javax.swing.*;
import java.awt.*;
import java.awt.image.BufferedImage;
import java.io.InputStream;
import java.util.Observable;
import java.util.Observer;

/**
 * VUE — responsabilités strictes MVC :
 *   • (4) Reçoit les notifications du Modèle via update()
 *   • (5) Consulte le Modèle (jeu.getEchiquier()) pour mettre à jour l'affichage
 *
 * La Vue n'écoute aucun événement Swing, ne modifie pas le Modèle et
 * n'appelle aucune méthode de traitement (setCoup, nouvellePartie…).
 * Elle expose des méthodes que le Contrôleur peut appeler pour des
 * effets locaux directs (étape 2 : surlignage, bordures, hover).
 */
public class VC extends JFrame implements Observer {

    // ── Référence au Modèle (lecture seule dans redraw) ──────────────────────
    private final Jeu jeu;

    // ── Composants Swing ─────────────────────────────────────────────────────
    private JPanel panel;
    private JLabel statusLabel;
    private final JPanel[][] casePanels = new JPanel[8][8];
    private final JLabel[][] caseLabels = new JLabel[8][8];

    // ── Couleurs (accessibles par le Contrôleur pour les effets locaux) ───────
    final Color BEIGE     = new Color(240, 217, 181);
    final Color MARRON    = new Color(181, 136, 99);
    final Color HIGHLIGHT = new Color(100, 200, 100);

    // ─────────────────────────────────────────────────────────────────────────

    public VC(Jeu jeu) {
        this.jeu = jeu;

        setTitle("Jeu d'échecs");
        setSize(650, 680);
        setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);

        panel = new JPanel(new BorderLayout());
        JPanel chessBoard = new JPanel(new GridLayout(8, 8));

        // Construire la grille — AUCUN MouseListener ici (rôle du Contrôleur)
        for (int l = 0; l < 8; l++) {
            for (int c = 0; c < 8; c++) {
                JPanel casePanel = new JPanel(new BorderLayout());
                casePanels[l][c] = casePanel;
                JLabel label = new JLabel("", SwingConstants.CENTER);
                caseLabels[l][c] = label;
                casePanel.add(label, BorderLayout.CENTER);
                chessBoard.add(casePanel);
            }
        }

        // Étiquettes de colonnes et de rangées
        JPanel rowPanel = new JPanel(new GridLayout(8, 1));
        for (int i = 8; i >= 1; i--) {
            JLabel lbl = new JLabel(" " + i + " ", SwingConstants.CENTER);
            lbl.setFont(new Font("SansSerif", Font.BOLD, 12));
            rowPanel.add(lbl);
        }
        JPanel colPanel = new JPanel(new GridLayout(1, 8));
        for (char c = 'a'; c <= 'h'; c++) {
            JLabel lbl = new JLabel(String.valueOf(c), SwingConstants.CENTER);
            lbl.setFont(new Font("SansSerif", Font.BOLD, 12));
            colPanel.add(lbl);
        }
        JPanel southContainer = new JPanel(new BorderLayout());
        southContainer.add(new JLabel("   "), BorderLayout.WEST);
        southContainer.add(colPanel, BorderLayout.CENTER);

        // Barre de statut
        statusLabel = new JLabel("Tour : BLANCS", SwingConstants.CENTER);
        statusLabel.setFont(new Font("SansSerif", Font.BOLD, 14));
        statusLabel.setBorder(BorderFactory.createEmptyBorder(4, 0, 4, 0));

        panel.add(statusLabel, BorderLayout.NORTH);
        panel.add(rowPanel, BorderLayout.WEST);
        panel.add(chessBoard, BorderLayout.CENTER);
        panel.add(southContainer, BorderLayout.SOUTH);
        add(panel);

        redraw();
    }

    // ══════════════════════════════════════════════════════════════════════════
    // Accesseurs exposés au Contrôleur pour les effets locaux directs (étape 2)
    // ══════════════════════════════════════════════════════════════════════════

    /** Le Contrôleur y attache ses MouseListeners (étape 1). */
    public JPanel getCasePanel(int row, int col) { return casePanels[row][col]; }

    /** Le Contrôleur lit l'icône pour créer la fenêtre fantôme de drag. */
    public JLabel getCaseLabel(int row, int col)  { return caseLabels[row][col]; }

    public JPanel getPanel() { return panel; }

    /** Effet local direct — surlignage vert d'une case (étape 2). */
    public void setHighlight(int row, int col) {
        casePanels[row][col].setBackground(HIGHLIGHT);
        casePanels[row][col].revalidate();
        casePanels[row][col].repaint();
    }

    /** Effet local direct — suppression du surlignage (étape 2). */
    public void clearHighlight(int row, int col) {
        casePanels[row][col].setBackground(((row + col) % 2 == 0) ? BEIGE : MARRON);
        casePanels[row][col].revalidate();
        casePanels[row][col].repaint();
    }

    /** Effet local direct — couleur de survol (étape 2). */
    public void setHover(int row, int col) {
        casePanels[row][col].setBackground(Color.RED);
    }

    /** Effet local direct — restauration couleur normale (étape 2). */
    public void clearHover(int row, int col) {
        casePanels[row][col].setBackground(((row + col) % 2 == 0) ? BEIGE : MARRON);
    }

    /** Effet local direct — bordure de sélection (étape 2). */
    public void setCaseBorder(int row, int col, javax.swing.border.Border border) {
        casePanels[row][col].setBorder(border);
    }

    // ══════════════════════════════════════════════════════════════════════════
    // Observer — étapes 4 (notification) et 5 (consultation du Modèle)
    // ══════════════════════════════════════════════════════════════════════════

    @Override
    public void update(Observable o, Object arg) {
        SwingUtilities.invokeLater(() -> {
            redraw(); // étape 5 : consultation de jeu.getEchiquier()

            if (arg instanceof Coup) {
                Coup c = (Coup) arg;
                String type = c.getType();
                Joueur joueur = jeu.getJoueurCourant();
                String next = (joueur != null && joueur.isBlanc()) ? "NOIRS" : "BLANCS";
                switch (type == null ? "" : type) {
                    case "ECHEC":
                        statusLabel.setForeground(new Color(180, 0, 0));
                        statusLabel.setText("ÉCHEC ! — Tour : " + next); break;
                    case "ROQUE":
                        statusLabel.setForeground(new Color(0, 100, 180));
                        statusLabel.setText("ROQUE — Tour : " + next); break;
                    case "PRISE EN PASSANT":
                        statusLabel.setForeground(new Color(0, 120, 0));
                        statusLabel.setText("PRISE EN PASSANT — Tour : " + next); break;
                    case "PROMOTION":
                        statusLabel.setForeground(new Color(120, 0, 120));
                        statusLabel.setText("PROMOTION — Tour : " + next); break;
                    default:
                        statusLabel.setForeground(Color.BLACK);
                        statusLabel.setText("Tour : " + next);
                }
            } else if (arg instanceof String) {
                // Fin de partie : mise à jour de la barre de statut uniquement.
                // Le dialogue est géré par le Contrôleur (MF).
                statusLabel.setForeground(Color.RED);
                statusLabel.setText((String) arg);
            } else {
                // null → nouvelle partie / redraw simple
                statusLabel.setForeground(Color.BLACK);
                Joueur joueur = jeu.getJoueurCourant();
                statusLabel.setText("Tour : " + (joueur != null && joueur.isBlanc() ? "BLANCS" : "NOIRS"));
            }
        });
    }

    // ══════════════════════════════════════════════════════════════════════════
    // Rendu interne — étape 5 (la Vue consulte le Modèle)
    // ══════════════════════════════════════════════════════════════════════════

    private void redraw() {
        int panelW = Math.max(1, panel.getWidth());
        int panelH = Math.max(1, panel.getHeight());
        int cellW  = Math.max(1, panelW / 8);
        int cellH  = Math.max(1, panelH / 8);
        int iconSize = Math.max(32, Math.min(cellW, cellH));

        for (int l = 0; l < 8; l++) {
            for (int c = 0; c < 8; c++) {
                casePanels[l][c].setBackground(((l + c) % 2 == 0) ? BEIGE : MARRON);
                Piece piece = jeu.getEchiquier().getPiece(l, c); // ← consultation Modèle
                if (piece != null) {
                    String imagePath = piece.getImageName();
                    String resourcePath = null;
                    if (imagePath != null && !imagePath.isEmpty()) {
                        for (String ext : new String[]{".svg", ".png", ".jpeg", ".jpg"}) {
                            String candidate = "/Pieces/" + imagePath + ext;
                            if (getClass().getResource(candidate) != null) { resourcePath = candidate; break; }
                        }
                    }
                    caseLabels[l][c].setIcon(createSafeIcon(piece, resourcePath, iconSize));
                    caseLabels[l][c].setText("");
                } else {
                    caseLabels[l][c].setIcon(null);
                    caseLabels[l][c].setText("");
                }
            }
        }
        panel.revalidate();
        panel.repaint();
    }

    Icon createSafeIcon(Piece piece, String resourcePath, int size) {
        if (resourcePath != null) {
            try {
                if (resourcePath.toLowerCase().endsWith(".svg")) {
                    try (InputStream is = getClass().getResourceAsStream(resourcePath)) {
                        if (is != null) {
                            BufferedImage bi = SvgToPngConverter.loadSvgAsImage(is, size, size);
                            if (bi != null) return new ImageIcon(bi);
                        }
                    } catch (Exception ignored) {}
                }
                java.net.URL url = getClass().getResource(resourcePath);
                if (url != null) {
                    ImageIcon ii = new ImageIcon(url);
                    if (ii.getIconWidth() > 0)
                        return new ImageIcon(ii.getImage().getScaledInstance(size, size, Image.SCALE_SMOOTH));
                }
            } catch (Exception ignored) {}
        }
        // Repli : lettre dans un cercle
        String initial = piece.getClass().getSimpleName().substring(0, 1).toUpperCase();
        BufferedImage bi = new BufferedImage(size, size, BufferedImage.TYPE_INT_ARGB);
        Graphics2D g = bi.createGraphics();
        try {
            g.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);
            g.setColor(new Color(0, 0, 0, 0));
            g.fillRect(0, 0, size, size);
            g.setColor(piece.isBlanc() ? new Color(255, 255, 255, 230) : new Color(60, 60, 60, 230));
            g.fillOval(2, 2, size - 4, size - 4);
            g.setColor(piece.isBlanc() ? MARRON : BEIGE);
            Font font = new Font("SansSerif", Font.BOLD, Math.max(12, size / 2));
            g.setFont(font);
            FontMetrics fm = g.getFontMetrics();
            g.drawString(initial, (size - fm.stringWidth(initial)) / 2, (size - fm.getHeight()) / 2 + fm.getAscent());
        } finally { g.dispose(); }
        return new ImageIcon(bi);
    }
}

package org.model;

public class JHumain extends Joueur {

    private boolean blanc;

    public JHumain(Jeu jeu, boolean blanc) {
        super(jeu);
        this.blanc = blanc;
    }

    @Override
    public Coup getCoup() {
        synchronized (jeu) {
            try {
                jeu.wait();
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
            return jeu.nextC;
        }
    }

    @Override
    public boolean isBlanc() {
        return blanc;
    }
}

